/* SwarmIQ — embedded Noto Sans (subset: Latin + punctuation + currency, incl. ₹).
   Registers the font into jsPDF so the PDF export renders Unicode correctly.
   Generated from Noto Sans (OFL-1.1) via fontTools subsetting. Load AFTER jspdf.umd.min.js. */
(function () {
  if (!window.jspdf || !window.jspdf.jsPDF) {
    console.warn("[fonts] jsPDF not found — Noto Sans not registered");
    return;
  }
  var API = window.jspdf.jsPDF.API;
  var REG = "";
  var BOLD = "";
  API.events.push(["addFonts", function () {
    this.addFileToVFS("NotoSans-Regular.ttf", REG);
    this.addFont("NotoSans-Regular.ttf", "NotoSans", "normal");
    this.addFileToVFS("NotoSans-Bold.ttf", BOLD);
    this.addFont("NotoSans-Bold.ttf", "NotoSans", "bold");
  }]);
})();
